# Helper to generate remaining levels with real content patterns
# ═══════════════════════════════════════════════════════════════

def _gen_seerah_level(level, start_id, emoji, topic_ar, topic_en, lessons_data):
    """Generate lessons from structured data."""
    result = []
    for i, data in enumerate(lessons_data):
        result.append(_seerah_lesson(
            start_id + i, level, i + 1, emoji,
            {"ar": data["title_ar"], "en": data["title_en"], "de": data.get("title_de", data["title_en"]), "fr": data.get("title_fr", data["title_en"]), "tr": data.get("title_tr", data["title_en"]), "ru": data.get("title_ru", data["title_en"]), "sv": data.get("title_sv", data["title_en"]), "nl": data.get("title_nl", data["title_en"]), "el": data.get("title_el", data["title_en"])},
            data.get("method", "story_based"),
            data["content"],
            data["quiz"],
            data.get("xp", 25)
        ))
    return result

